                     || x.AddressLineTwo.Contains(search.Name)
                     || x.CityOrTown.Contains(search.Name))
                     && x.EmployeeId == search.RefId.Value,
                index: search.Page, size: search.Size, sortBy: search.SortBy ?? "AddressLineOne", ascending: !search.IsDescend);
